sql:
SELECT park_id, COUNT(*) AS staff_count
FROM park_staff
GROUP BY park_id;

SELECT p.park_id, p.site_address, lh.name, lh.contact_email
FROM parks p
JOIN license_holders lh ON p.license_holder_id = lh.license_holder_id;

SELECT staff_id, name, email, role, park_id, phone_number
FROM park_staff
WHERE role = 'manager';

SELECT site_address 
FROM parks 
WHERE license_holder_id IS NOT NULL;

SELECT park_staff.name, notifications.message
FROM park_staff
JOIN notifications ON park_staff.staff_id = notifications.staff_id;

SELECT p.park_id, COUNT(DISTINCT p.license_holder_id) AS num_license_holders
FROM parks p
GROUP BY p.park_id;

SELECT name, email
FROM park_visitors
WHERE visit_date = '2022-01-01' AND park_id = 1;

SELECT COUNT(*)
FROM notifications n
WHERE n.type = 'reminder';

SELECT ps.staff_id, ps.name, ua.username
FROM park_staff ps
JOIN user_accounts ua ON ps.staff_id = ua.staff_id;
